// ---- UI Testing with Compose ----
// Dependencies:
// androidTestImplementation("androidx.compose.ui:ui-test-junit4:1.5.0")
// androidTestImplementation("androidx.compose.ui:ui-test-manifest:1.5.0")

// ---- Compose UI Test ----
@OptIn(ExperimentalTestApi::class)
class ComposeUITest {
    @get:Rule
    val composeTestRule = createComposeRule()

    @Test
    fun testCounterUI() {
        composeTestRule.setContent {
            CounterApp()
        }

        // Check initial state
        composeTestRule.onNodeWithText("Count: 0").assertExists()

        // Click increment button
        composeTestRule.onNodeWithText("+").performClick()
        composeTestRule.onNodeWithText("Count: 1").assertExists()

        // Click decrement button
        composeTestRule.onNodeWithText("-").performClick()
        composeTestRule.onNodeWithText("Count: 0").assertExists()

        // Click reset button
        composeTestRule.onNodeWithText("Reset").performClick()
        composeTestRule.onNodeWithText("Count: 0").assertExists()
    }

    @Test
    fun testAddNoteUI() {
        composeTestRule.setContent {
            NotesScreen()
        }

        // Add a note
        composeTestRule.onNodeWithText("Add Note").performClick()

        composeTestRule.onNodeWithText("Title").performTextInput("Test Note")
        composeTestRule.onNodeWithText("Content").performTextInput("Test Content")
        composeTestRule.onNodeWithText("Add").performClick()

        // Verify note appears
        composeTestRule.onNodeWithText("Test Note").assertExists()
        composeTestRule.onNodeWithText("Test Content").assertExists()
    }

    @Test
    fun testDeleteNoteUI() {
        composeTestRule.setContent {
            NotesScreen()
        }

        // Add a note
        composeTestRule.onNodeWithText("Add Note").performClick()
        composeTestRule.onNodeWithText("Title").performTextInput("Note to Delete")
        composeTestRule.onNodeWithText("Content").performTextInput("Content")
        composeTestRule.onNodeWithText("Add").performClick()

        // Select and delete
        composeTestRule.onNodeWithText("Note to Delete").performClick()
        composeTestRule.onNodeWithText("Delete").performClick()

        // Verify deleted
        composeTestRule.onNodeWithText("Note to Delete").assertDoesNotExist()
    }

    @Test
    fun testSearchUI() {
        composeTestRule.setContent {
            NotesScreen()
        }

        // Add test notes
        addNote("Apple", "Fruit")
        addNote("Banana", "Fruit")
        addNote("Carrot", "Vegetable")

        // Search
        composeTestRule.onNodeWithText("Search notes...").performTextInput("Apple")

        // Verify results
        composeTestRule.onNodeWithText("Apple").assertExists()
        composeTestRule.onNodeWithText("Banana").assertDoesNotExist()
        composeTestRule.onNodeWithText("Carrot").assertDoesNotExist()
    }
}

// ---- Test with ViewModel ----
@OptIn(ExperimentalTestApi::class)
class ViewModelUITest {
    @get:Rule
    val composeTestRule = createComposeRule()

    @Test
    fun testViewModelUI() {
        val viewModel = TestViewModel()

        composeTestRule.setContent {
            TestScreen(viewModel)
        }

        // Initial state
        composeTestRule.onNodeWithText("Loading...").assertExists()

        // Wait for data
        composeTestRule.waitForIdle()

        // Data loaded
        composeTestRule.onNodeWithText("Data loaded!").assertExists()
    }
}

// ---- Test with animations ----
@OptIn(ExperimentalTestApi::class)
class AnimationTest {
    @get:Rule
    val composeTestRule = createComposeRule()

    @Test
    fun testAnimation() {
        composeTestRule.setContent {
            AnimatedScreen()
        }

        // Wait for animation
        composeTestRule.waitForIdle()

        // Check final state
        composeTestRule.onNodeWithText("Animated!").assertExists()
    }
}

// ---- Test helpers ----
fun ComposeTestRule.addNote(title: String, content: String) {
    onNodeWithText("Add Note").performClick()
    onNodeWithText("Title").performTextInput(title)
    onNodeWithText("Content").performTextInput(content)
    onNodeWithText("Add").performClick()
}

// ---- UI Test with screenshot ----
@OptIn(ExperimentalTestApi::class)
class ScreenshotTest {
    @get:Rule
    val composeTestRule = createComposeRule()

    @Test
    fun testScreenshot() {
        composeTestRule.setContent {
            MainScreen()
        }

        // Take screenshot
        composeTestRule.onRoot().captureToImage()
    }
}

